1	import type {
2	  BinaryPaths,
3	  Generator as IGenerator,
4	  GeneratorConfig,
5	  GeneratorManifest,
6	  GeneratorOptions,
7	} from '@prisma/generator'
8	import { GeneratorProcess } from '@prisma/generator-helper'
