10	import { parseEnvValue } from './utils/parseEnvValue'
11	
12	export abstract class Generator {
13	  public manifest: GeneratorManifest | null = null
14	  public config: GeneratorConfig
15	  public options?: GeneratorOptions
16	
17	  constructor(config: GeneratorConfig) {
18	    this.config = config
19	  }
20	
21	  async init(): Promise<void> {
22	    await this.initImpl()
23	    this.manifest = await this.getManifest()
24	  }
25	
26	  protected abstract initImpl(): Promise<void>
27	
28	  protected abstract getManifest(): Promise<GeneratorManifest | null>
29	
30	  abstract stop(): void
31	
32	  generate(): Promise<void> {
33	    if (!this.options) {
34	      throw new Error(`Please first run .setOptions() on the Generator to initialize the options`)
35	    }
36	    return this.generateImpl(this.options)
37	  }
38	
39	  protected abstract generateImpl(options: GeneratorOptions): Promise<void>
40	
41	  setOptions(options: GeneratorOptions): void {
42	    this.options = options
43	  }
44	
45	  setBinaryPaths(binaryPaths: BinaryPaths): void {
46	    if (!this.options) {
47	      throw new Error(`Please first run .setOptions() on the Generator to initialize the options`)
48	    }
49	    this.options.binaryPaths = binaryPaths
50	  }
51	
52	  /**
53	   * Returns the pretty name of the generator specified in the manifest (e.g.,
54	   * "Prisma Client"), or, if the former is not defined, the generator's
55	   * provider name (e.g., "prisma-client-js") as a fallback.
56	   */
57	  getPrettyName(): string {
58	    return this.manifest?.prettyName ?? this.getProvider()
59	  }
60	
61	  /**
62	   * Returns the provider name, parsed and resolved from environment variable
63	   * if necessary.
64	   */
65	  getProvider(): string {
66	    return parseEnvValue(this.config.provider)
67	  }
68	}
