70	export class JsonRpcGenerator extends Generator {
71	  #generatorProcess: GeneratorProcess
72	
73	  constructor(executablePath: string, config: GeneratorConfig, isNode?: boolean) {
74	    super(config)
75	    this.#generatorProcess = new GeneratorProcess(executablePath, { isNode })
76	  }
77	
78	  protected override async initImpl(): Promise<void> {
79	    await this.#generatorProcess.init()
80	  }
81	
82	  protected override async getManifest(): Promise<GeneratorManifest | null> {
83	    return await this.#generatorProcess.getManifest(this.config)
84	  }
85	
86	  protected override async generateImpl(options: GeneratorOptions): Promise<void> {
87	    await this.#generatorProcess.generate(options)
88	  }
89	
90	  override stop(): void {
91	    this.#generatorProcess.stop()
92	  }
93	}
