95	export class InProcessGenerator extends Generator {
96	  #generator: IGenerator
97	
98	  constructor(config: GeneratorConfig, generator: IGenerator) {
99	    super(config)
100	    this.#generator = generator
101	  }
102	
103	  protected override async initImpl(): Promise<void> {}
104	
105	  protected override async getManifest(): Promise<GeneratorManifest | null> {
106	    return await this.#generator.getManifest(this.config)
107	  }
108	
109	  protected override async generateImpl(options: GeneratorOptions): Promise<void> {
110	    await this.#generator.generate(options)
111	  }
112	
113	  override stop(): void {}
114	}
