const scalarTypeMap: Record<string, string> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Boolean: 'boolean',
  BigInt: 'string',
  DateTime: 'string',
  Decimal: 'string',
  Json: 'unknown',
  Bytes: 'string',
