import type * as DMMF from '@prisma/dmmf'

import { mapScalarType } from './type-mapping'

export function lowerFirst(str: string): string {
  return str.charAt(0).toLowerCase() + str.slice(1)
}

export function pluralize(str: string): string {
  if (str.endsWith('s') || str.endsWith('x') || str.endsWith('z') || str.endsWith('ch') || str.endsWith('sh')) {
    return str + 'es'
  }
  if (str.endsWith('y') && !/[aeiou]y$/i.test(str)) {
    return str.slice(0, -1) + 'ies'
  }
  return str + 's'
}

export function generateFileHeader(): string {
  return [
    '/* eslint-disable */',
    '// Auto-generated by @prisma/generator-rest-client — do not edit.',
    '',
  ].join('\n')
}

function resolveFieldType(field: DMMF.Field, enumNames: readonly string[]): string {
  let tsType: string

  if (field.kind === 'enum' || enumNames.includes(field.type)) {
    tsType = field.type
  } else {
    tsType = mapScalarType(field.type)
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }

  if (!field.isRequired && !field.isList) {
    tsType = `${tsType} | null`
  }

  return tsType
}

function isScalarOrEnum(field: DMMF.Field): boolean {
  return field.kind === 'scalar' || field.kind === 'enum'
}

export function generateEnumType(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${values}`
}

export function generateModelInterface(model: DMMF.Model, enumNames: readonly string[]): string {
  const fields = model.fields.filter(isScalarOrEnum)

  const lines = fields.map((field) => {
    const tsType = resolveFieldType(field, enumNames)
    return `  ${field.name}: ${tsType}`
  })

  return [`export interface ${model.name} {`, ...lines, '}'].join('\n')
}

function isAutoGeneratedField(field: DMMF.Field): boolean {
  return Boolean(
    (field.isId && field.hasDefaultValue) || field.isUpdatedAt || field.isGenerated || field.isReadOnly,
  )
}

export function generateCreateInput(model: DMMF.Model, enumNames: readonly string[]): string {
  const fields = model.fields.filter(isScalarOrEnum).filter((f) => !isAutoGeneratedField(f))

  const lines = fields.map((field) => {
    const tsType = resolveFieldType(field, enumNames)
    const optional = field.hasDefaultValue || !field.isRequired ? '?' : ''
    return `  ${field.name}${optional}: ${tsType}`
  })

  return [`export interface ${model.name}CreateInput {`, ...lines, '}'].join('\n')
}

export function generateUpdateInput(model: DMMF.Model, enumNames: readonly string[]): string {
  const fields = model.fields.filter(isScalarOrEnum).filter((f) => !f.isId && !f.isReadOnly)

  const lines = fields.map((field) => {
    const tsType = resolveFieldType(field, enumNames)
    return `  ${field.name}?: ${tsType}`
  })

  return [`export interface ${model.name}UpdateInput {`, ...lines, '}'].join('\n')
}

function findIdField(model: DMMF.Model): DMMF.Field | undefined {
  return model.fields.find((f) => f.isId)
}

export function generateModelDelegate(model: DMMF.Model, enumNames: readonly string[]): string {
  const name = model.name
  const endpoint = '/' + lowerFirst(pluralize(name))
  const idField = findIdField(model)
  const idType = idField ? mapScalarType(idField.type) : 'string'
  const idName = idField ? idField.name : 'id'

  return `class ${name}Delegate {
  #baseUrl: string
  #headers: Record<string, string>

  constructor(baseUrl: string, headers: Record<string, string>) {
    this.#baseUrl = baseUrl
    this.#headers = headers
  }

  async findMany(): Promise<${name}[]> {
    return this.#request<${name}[]>('GET', '${endpoint}')
  }

  async findUnique(args: { where: { ${idName}: ${idType} } }): Promise<${name} | null> {
    return this.#request<${name} | null>('GET', \`${endpoint}/\${args.where.${idName}}\`)
  }

  async create(args: { data: ${name}CreateInput }): Promise<${name}> {
    return this.#request<${name}>('POST', '${endpoint}', args.data)
  }

  async update(args: { where: { ${idName}: ${idType} }; data: ${name}UpdateInput }): Promise<${name}> {
    return this.#request<${name}>('PUT', \`${endpoint}/\${args.where.${idName}}\`, args.data)
  }

  async delete(args: { where: { ${idName}: ${idType} } }): Promise<${name}> {
    return this.#request<${name}>('DELETE', \`${endpoint}/\${args.where.${idName}}\`)
  }

  async #request<T>(method: string, path: string, body?: unknown): Promise<T> {
    const response = await fetch(\`\${this.#baseUrl}\${path}\`, {
      method,
      headers: { 'Content-Type': 'application/json', ...this.#headers },
      body: body !== undefined ? JSON.stringify(body) : undefined,
    })
    if (!response.ok) {
      throw new Error(\`REST client error: \${response.status} \${response.statusText}\`)
    }
    return response.json() as Promise<T>
  }
}`
}

export function generateClientClass(models: readonly DMMF.Model[], enumNames: readonly string[]): string {
  const properties = models.map((m) => `  readonly ${lowerFirst(m.name)}: ${m.name}Delegate`)
  const assignments = models.map(
    (m) => `    this.${lowerFirst(m.name)} = new ${m.name}Delegate(baseUrl, headers)`,
  )

  return [
    'export class RestClient {',
    ...properties,
    '',
    '  constructor(baseUrl: string, headers: Record<string, string> = {}) {',
    ...assignments,
    '  }',
    '}',
  ].join('\n')
}

