import type * as DMMF from '@prisma/dmmf'

import {
  generateClientClass,
  generateCreateInput,
  generateEnumType,
  generateFileHeader,
  generateModelDelegate,
  generateModelInterface,
  generateUpdateInput,
} from './template'

/**
 * Generates a typed REST API client from a Prisma DMMF document.
 *
 * This is a pure function (no I/O) — it takes DMMF and returns
 * the complete TypeScript source for the generated client.
 */
export function generateRestClient(dmmf: DMMF.Document): string {
  const { models, enums } = dmmf.datamodel
  const enumNames = enums.map((e) => e.name)

  const parts: string[] = []

  parts.push(generateFileHeader())

  for (const enumDef of enums) {
    parts.push(generateEnumType(enumDef))
  }

  for (const model of models) {
    parts.push(generateModelInterface(model, enumNames))
    parts.push(generateCreateInput(model, enumNames))
    parts.push(generateUpdateInput(model, enumNames))
  }

  for (const model of models) {
    parts.push(generateModelDelegate(model, enumNames))
  }

  parts.push(generateClientClass(models, enumNames))

  return parts.join('\n\n') + '\n'
}

