import { describe, expect, test } from 'vitest'

import type * as DMMF from '@prisma/dmmf'

import {
  generateClientClass,
  generateCreateInput,
  generateEnumType,
  generateFileHeader,
  generateModelDelegate,
  generateModelInterface,
  generateUpdateInput,
  lowerFirst,
  pluralize,
} from '../template'

function field(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  }
}

function model(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  }
}

describe('lowerFirst', () => {
  test('lowercases the first character', () => {
    expect(lowerFirst('User')).toBe('user')
    expect(lowerFirst('PostComment')).toBe('postComment')
  })

  test('handles single character', () => {
    expect(lowerFirst('A')).toBe('a')
  })

  test('handles empty string', () => {
    expect(lowerFirst('')).toBe('')
  })
})

describe('pluralize', () => {
  test('adds s to regular words', () => {
    expect(pluralize('user')).toBe('users')
    expect(pluralize('post')).toBe('posts')
  })

  test('adds es to words ending in s, x, z, ch, sh', () => {
    expect(pluralize('class')).toBe('classes')
    expect(pluralize('box')).toBe('boxes')
    expect(pluralize('buzz')).toBe('buzzes')
    expect(pluralize('match')).toBe('matches')
    expect(pluralize('dish')).toBe('dishes')
  })

  test('changes y to ies for consonant+y', () => {
    expect(pluralize('category')).toBe('categories')
    expect(pluralize('company')).toBe('companies')
  })

  test('adds s to vowel+y', () => {
    expect(pluralize('key')).toBe('keys')
    expect(pluralize('day')).toBe('days')
  })
})

describe('generateFileHeader', () => {
  test('includes eslint-disable and auto-generated comment', () => {
    const header = generateFileHeader()
    expect(header).toContain('eslint-disable')
