        field({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
        field({ name: 'email', type: 'String', isUnique: true }),
        field({ name: 'name', type: 'String', isRequired: false }),
      ]),
    ])

    const result = generateRestClient(dmmf)

    expect(result).toContain('eslint-disable')
    expect(result).toContain('Auto-generated')

    expect(result).toContain('export interface User {')
    expect(result).toContain('  id: number')
    expect(result).toContain('  email: string')
    expect(result).toContain('  name: string | null')

    expect(result).toContain('export interface UserCreateInput {')
    expect(result).toContain('export interface UserUpdateInput {')

    expect(result).toContain('class UserDelegate')
    expect(result).toContain('findMany')
    expect(result).toContain('findUnique')
    expect(result).toContain('create')
    expect(result).toContain('update')
    expect(result).toContain('delete')

    expect(result).toContain('export class RestClient {')
    expect(result).toContain('readonly user: UserDelegate')
  })

  test('generates enum types from DMMF enums', () => {
    const dmmf = createTestDmmf(
      [
        model('User', [
          field({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
          field({ name: 'role', type: 'Role', kind: 'enum', hasDefaultValue: true, default: 'USER' }),
        ]),
      ],
      [
        {
          name: 'Role',
          values: [
            { name: 'ADMIN', dbName: null },
            { name: 'USER', dbName: null },
          ],
        },
      ],
    )

    const result = generateRestClient(dmmf)

    expect(result).toContain("export type Role = 'ADMIN' | 'USER'")
    expect(result).toContain('role: Role')
  })

  test('excludes relation fields from model interfaces', () => {
    const dmmf = createTestDmmf([
      model('Post', [
        field({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        field({ name: 'title', type: 'String' }),
        field({ name: 'authorId', type: 'Int', isReadOnly: true }),
        field({
          name: 'author',
          type: 'User',
          kind: 'object',
          relationName: 'PostToUser',
          relationFromFields: ['authorId'],
          relationToFields: ['id'],
        }),
      ]),
    ])

    const result = generateRestClient(dmmf)

    expect(result).toContain('  title: string')
    expect(result).toContain('  authorId: number')
    expect(result).not.toMatch(/^\s+author: User/m)
  })

  test('handles list fields correctly', () => {
    const dmmf = createTestDmmf([
      model('User', [
        field({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        field({ name: 'tags', type: 'String', isList: true }),
      ]),
    ])

    const result = generateRestClient(dmmf)
    expect(result).toContain('  tags: string[]')
  })

  test('handles multiple models', () => {
    const dmmf = createTestDmmf([
      model('User', [
        field({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        field({ name: 'email', type: 'String' }),
      ]),
      model('Post', [
        field({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        field({ name: 'title', type: 'String' }),
      ]),
    ])

    const result = generateRestClient(dmmf)

    expect(result).toContain('export interface User {')
    expect(result).toContain('export interface Post {')
    expect(result).toContain('class UserDelegate')
    expect(result).toContain('class PostDelegate')
    expect(result).toContain('readonly user: UserDelegate')
    expect(result).toContain('readonly post: PostDelegate')
  })

  test('generates valid output for empty models list', () => {
    const dmmf = createTestDmmf([])

    const result = generateRestClient(dmmf)

    expect(result).toContain('export class RestClient {')
    expect(result).toContain('constructor')
  })

  test('handles model with string id', () => {
    const dmmf = createTestDmmf([
      model('User', [
        field({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
        field({ name: 'name', type: 'String' }),
      ]),
    ])

    const result = generateRestClient(dmmf)
    expect(result).toContain('where: { id: string }')
  })

  test('auto-increment id is omitted from CreateInput', () => {
    const dmmf = createTestDmmf([
      model('User', [
        field({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        field({ name: 'email', type: 'String' }),
      ]),
    ])

    const result = generateRestClient(dmmf)

    const createInputBlock = result.slice(
      result.indexOf('export interface UserCreateInput {'),
      result.indexOf('}', result.indexOf('export interface UserCreateInput {')) + 1,
    )
    expect(createInputBlock).not.toContain('id')
    expect(createInputBlock).toContain('email: string')
  })
})

