import os from 'node:os'
import path from 'node:path'

import { afterEach, beforeEach, describe, expect, test } from 'vitest'

import type * as DMMF from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'

import { onGenerate } from '../generator'

function createTestDmmf(): DMMF.Document {
  return {
    datamodel: {
      models: [
        {
          name: 'User',
          dbName: null,
          schema: null,
          fields: [
            {
              kind: 'scalar',
              name: 'id',
              type: 'Int',
              isRequired: true,
              isList: false,
              isUnique: false,
              isId: true,
              isReadOnly: false,
              hasDefaultValue: true,
              default: { name: 'autoincrement', args: [] },
            },
            {
              kind: 'scalar',
              name: 'email',
              type: 'String',
              isRequired: true,
              isList: false,
              isUnique: true,
              isId: false,
              isReadOnly: false,
              hasDefaultValue: false,
            },
          ],
          uniqueFields: [],
          uniqueIndexes: [],
          primaryKey: null,
        },
      ],
      enums: [],
      types: [],
      indexes: [],
    },
    schema: {
      inputObjectTypes: { prisma: [] },
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  }
}

describe('onGenerate', () => {
  let tmpDir: string

  beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'prisma-gen-rest-'))
  })

  afterEach(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true })
  })

  test('writes rest-client.ts to the output directory', async () => {
    const outputDir = path.join(tmpDir, 'generated', 'rest-client')

    const options = {
      generator: {
        name: 'restClient',
        provider: { fromEnvVar: null, value: 'prisma-generator-rest-client' },
        output: { fromEnvVar: null, value: outputDir },
        config: {},
        binaryTargets: [],
        previewFeatures: [],
        sourceFilePath: '/test/schema.prisma',
      },
      otherGenerators: [],
      schemaPath: '/test/schema.prisma',
      dmmf: createTestDmmf(),
      datasources: [],
      datamodel: '',
      version: 'test',
    } as GeneratorOptions

    await onGenerate(options)

    const outputFile = path.join(outputDir, 'rest-client.ts')
    expect(fs.existsSync(outputFile)).toBe(true)

    const content = fs.readFileSync(outputFile, 'utf-8')
    expect(content).toContain('export interface User {')
    expect(content).toContain('export class RestClient {')
    expect(content).toContain('class UserDelegate')
  })

  test('throws when output is not specified', async () => {
    const options = {
      generator: {
        name: 'restClient',
        provider: { fromEnvVar: null, value: 'prisma-generator-rest-client' },
        output: null,
        config: {},
        binaryTargets: [],
        previewFeatures: [],
        sourceFilePath: '/test/schema.prisma',
      },
      otherGenerators: [],
      schemaPath: '/test/schema.prisma',
      dmmf: createTestDmmf(),
      datasources: [],
      datamodel: '',
      version: 'test',
    } as GeneratorOptions

    await expect(onGenerate(options)).rejects.toThrow('No output directory specified')
  })

  test('creates nested output directories', async () => {
    const outputDir = path.join(tmpDir, 'deep', 'nested', 'output')

    const options = {
      generator: {
        name: 'restClient',
        provider: { fromEnvVar: null, value: 'prisma-generator-rest-client' },
        output: { fromEnvVar: null, value: outputDir },
        config: {},
        binaryTargets: [],
        previewFeatures: [],
        sourceFilePath: '/test/schema.prisma',
      },
      otherGenerators: [],
      schemaPath: '/test/schema.prisma',
      dmmf: createTestDmmf(),
      datasources: [],
      datamodel: '',
      version: 'test',
    } as GeneratorOptions

    await onGenerate(options)

    expect(fs.existsSync(path.join(outputDir, 'rest-client.ts'))).toBe(true)
  })
})

